@namespace Lumeo

@{
    var subContext = new ContextMenuSubContext(
        _open,
        EventCallback.Factory.Create<bool>(this, SetOpen),
        _wrapperId,
        _triggerId,
        _contentId,
        EventCallback.Factory.Create(this, CloseTree),
        ScheduleClose,
        CancelClose);
}

<CascadingValue Value="subContext" IsFixed="false">
    <div id="@_wrapperId" class="relative" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [CascadingParameter] public ContextMenu.ContextMenuContext? RootContext { get; set; }
    [CascadingParameter] public ContextMenuSubContext? ParentSubContext { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _open;
    private readonly string _wrapperId = LumeoIds.New("context-sub");
    internal readonly string _triggerId = LumeoIds.New("context-sub-trigger");
    internal readonly string _contentId = LumeoIds.New("context-sub-content");

    private CancellationTokenSource? _closeCts;

    private async Task SetOpen(bool value)
    {
        if (_open == value) return;
        _open = value;
        await InvokeAsync(StateHasChanged);
    }

    private async Task CloseTree()
    {
        await SetOpen(false);
        if (ParentSubContext is not null)
        {
            await ParentSubContext.CloseTree.InvokeAsync();
        }
        else if (RootContext is not null)
        {
            await RootContext.SetOpen.InvokeAsync(false);
        }
    }

    private void CancelClose()
    {
        try { _closeCts?.Cancel(); } catch (ObjectDisposedException) { }
        _closeCts?.Dispose();
        _closeCts = null;
    }

    private void ScheduleClose()
    {
        CancelClose();
        _closeCts = new CancellationTokenSource();
        var token = _closeCts.Token;
        _ = Task.Run(async () =>
        {
            try { await Task.Delay(200, token); }
            catch (TaskCanceledException) { return; }
            if (token.IsCancellationRequested) return;
            await InvokeAsync(async () => await SetOpen(false));
        });
    }

    public record ContextMenuSubContext(
        bool IsOpen,
        EventCallback<bool> SetOpen,
        string WrapperId,
        string TriggerId,
        string ContentId,
        EventCallback CloseTree,
        Action ScheduleClose,
        Action CancelClose);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (SubContext.IsOpen)
{
    <div id="@SubContext.ContentId"
         role="menu"
         aria-orientation="vertical"
         class="@CssClass"
         tabindex="-1"
         @onkeydown="HandleKeyDown"
         @onmouseenter="HandleMouseEnter"
         @onmouseleave="HandleMouseLeave"
         @onmousedown:stopPropagation="true"
         @ontouchstart:stopPropagation="true"
         @attributes="AdditionalAttributes">
        @ChildContent
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public ContextMenuSub.ContextMenuSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _positioned;
    private int _focusedIndex = -1;

    private string CssClass => $"fixed z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (SubContext.IsOpen && !_positioned)
        {
            await PositionWithFlip();
            _positioned = true;
            _focusedIndex = -1;
        }
        else if (!SubContext.IsOpen && _positioned)
        {
            await Cleanup();
        }
    }

    private async Task PositionWithFlip()
    {
        var side = "right";
        try
        {
            var triggerRect = await Interop.GetElementRect(SubContext.TriggerId);
            var viewport = await Interop.GetViewportSize();
            if (triggerRect is not null && triggerRect.X + triggerRect.Width + 200 > viewport.Width)
            {
                side = "left";
            }
        }
        catch (JSDisconnectedException) { }

        await Interop.PositionFixed(SubContext.ContentId, SubContext.TriggerId, "start", false, side);
    }

    private Task HandleMouseEnter()
    {
        SubContext.CancelClose();
        return Task.CompletedTask;
    }

    private void HandleMouseLeave()
    {
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await SubContext.CloseTree.InvokeAsync();
                break;
            case "ArrowLeft":
                SubContext.CancelClose();
                await SubContext.SetOpen.InvokeAsync(false);
                try { await Interop.FocusElement(SubContext.TriggerId); } catch (JSDisconnectedException) { }
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(SubContext.ContentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(SubContext.ContentId, _focusedIndex);
                    }
                    break;
                }
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(SubContext.ContentId); } catch (JSDisconnectedException) { }
        _positioned = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_positioned) await Cleanup();
    }
}

@namespace Lumeo

<button id="@SubContext.TriggerId"
        type="button"
        role="menuitem"
        tabindex="-1"
        class="@CssClass"
        data-state="@(SubContext.IsOpen ? "open" : "closed")"
        aria-haspopup="menu"
        aria-expanded="@SubContext.IsOpen.ToString().ToLower()"
        aria-controls="@SubContext.ContentId"
        disabled="@Disabled"
        @onclick="HandleClick"
        @onmouseenter="HandleMouseEnter"
        @onmouseleave="HandleMouseLeave"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @ChildContent
    <Blazicon Svg="Lucide.ChevronRight" class="ml-auto h-4 w-4" />
</button>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public ContextMenuSub.ContextMenuSubContext SubContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => $"relative flex w-full cursor-default select-none items-center gap-2 rounded-sm px-2 py-1.5 min-h-11 sm:min-h-0 text-sm outline-none transition-colors hover:bg-accent hover:text-accent-foreground focus:bg-accent focus:text-accent-foreground data-[state=open]:bg-accent data-[state=open]:text-accent-foreground disabled:pointer-events-none disabled:opacity-50 disabled:cursor-not-allowed {Class}".Trim();

    private async Task HandleClick()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        await SubContext.SetOpen.InvokeAsync(!SubContext.IsOpen);
    }

    private async Task HandleMouseEnter()
    {
        if (Disabled) return;
        SubContext.CancelClose();
        if (!SubContext.IsOpen)
        {
            await SubContext.SetOpen.InvokeAsync(true);
        }
    }

    private void HandleMouseLeave()
    {
        if (!SubContext.IsOpen) return;
        SubContext.ScheduleClose();
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowRight":
            case "Enter":
            case " ":
                SubContext.CancelClose();
                if (!SubContext.IsOpen)
                {
                    await SubContext.SetOpen.InvokeAsync(true);
                }
                _ = InvokeAsync(async () =>
                {
                    await Task.Delay(20);
                    try { await Interop.FocusMenuItemByIndex(SubContext.ContentId, 0); }
                    catch (JSDisconnectedException) { }
                });
                break;
        }
    }
}

@namespace Lumeo
@implements IAsyncDisposable

<div id="@_triggerId"
     class="@CssClass"
     style="@InlineStyle"
     aria-expanded="@Context.IsOpen"
     @oncontextmenu="HandleContextMenu" @oncontextmenu:preventDefault
     @onkeydown="HandleKeyDown"
     @ontouchstart="HandleTouchStart"
     @ontouchmove="HandleTouchMove"
     @ontouchend="HandleTouchEnd"
     @ontouchcancel="HandleTouchEnd"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public ContextMenu.ContextMenuContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    /// <summary>
    /// Duration in milliseconds a touch must remain on the trigger (without
    /// significant movement) before the context menu opens. Default: 500ms.
    /// </summary>
    [Parameter] public int LongPressMs { get; set; } = 500;

    /// <summary>
    /// Pixel threshold for touch movement that cancels the long-press timer.
    /// Above this, the user is interpreted as scrolling, not long-pressing.
    /// </summary>
    [Parameter] public double MoveTolerancePx { get; set; } = 10.0;

    private readonly string _triggerId = LumeoIds.New("ctx-trigger");

    private CancellationTokenSource? _longPressCts;
    private double _touchStartX;
    private double _touchStartY;

    // touch-action: manipulation keeps native scroll working but disables
    // double-tap-to-zoom. -webkit-touch-callout: none + user-select: none
    // suppresses iOS Safari's default long-press callout (share/select sheet)
    // so our 500ms timer is the only thing that fires.
    private string InlineStyle => "touch-action: manipulation; -webkit-touch-callout: none; user-select: none;";

    private string CssClass => $"inline-flex {Class}".Trim();

    private async Task HandleContextMenu(MouseEventArgs e)
    {
        await Context.SetPosition.InvokeAsync((e.ClientX, e.ClientY));
        await Context.SetOpen.InvokeAsync(true);
    }

    // Keyboard activation: Shift+F10 or the dedicated Menu key opens the context
    // menu positioned at the bottom-left corner of the trigger element.
    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "ContextMenu" || (e.ShiftKey && e.Key == "F10"))
        {
            var rect = await Interop.GetElementRect(_triggerId);
            var x = rect?.X ?? 0;
            var y = rect is not null ? rect.Y + rect.Height : 0;
            await Context.SetPosition.InvokeAsync((x, y));
            await Context.SetOpen.InvokeAsync(true);
        }
    }

    // --- Long-press touch path (iOS Safari fix) ---
    //
    // iOS Safari does not reliably fire `contextmenu` for non-text content on
    // long-press, so we run a parallel touch timer. On touchstart we record the
    // initial position and start a 500ms delay. If the user moves more than
    // MoveTolerancePx pixels (= scrolling) or lifts the finger (= tap) before
    // the timer elapses, we cancel. When the timer fires uncancelled, we open
    // the menu at the touch coordinates and emit a short haptic pulse.

    private async Task HandleTouchStart(TouchEventArgs e)
    {
        if (e.Touches.Length == 0) return;

        var touch = e.Touches[0];
        _touchStartX = touch.ClientX;
        _touchStartY = touch.ClientY;

        CancelLongPress();
        _longPressCts = new CancellationTokenSource();
        var token = _longPressCts.Token;
        var x = touch.ClientX;
        var y = touch.ClientY;

        try
        {
            await Task.Delay(LongPressMs, token);
        }
        catch (TaskCanceledException)
        {
            return;
        }

        if (token.IsCancellationRequested) return;

        // Long-press fired. Open at the original touch position and pulse haptics.
        await Context.SetPosition.InvokeAsync((x, y));
        await Context.SetOpen.InvokeAsync(true);
        await Interop.Vibrate(50);
    }

    private void HandleTouchMove(TouchEventArgs e)
    {
        if (_longPressCts is null || e.Touches.Length == 0) return;

        var touch = e.Touches[0];
        var dx = touch.ClientX - _touchStartX;
        var dy = touch.ClientY - _touchStartY;
        if ((dx * dx + dy * dy) > (MoveTolerancePx * MoveTolerancePx))
        {
            CancelLongPress();
        }
    }

    private void HandleTouchEnd(TouchEventArgs e) => CancelLongPress();

    private void CancelLongPress()
    {
        if (_longPressCts is null) return;
        try { _longPressCts.Cancel(); } catch (ObjectDisposedException) { }
        _longPressCts.Dispose();
        _longPressCts = null;
    }

    public ValueTask DisposeAsync()
    {
        CancelLongPress();
        return ValueTask.CompletedTask;
    }
}
